import React, { useState, useEffect, useRef } from 'react';
import { io, Socket } from 'socket.io-client';
import { format } from 'date-fns';
import styled, { createGlobalStyle, keyframes } from 'styled-components';

// ===== Types =====
interface TradePosition {
  id: string;
  tokenMint: string;
  tokenName: string;
  tokenSymbol: string;
  entryPrice: number;
  entryMarketCap: number;
  amount: number;
  solAmount: number;
  buyRank: number;
  totalBuyersAtEntry: number;
  buyTime: number;
  graduated: boolean;
  graduatedAt?: number;
  sold: boolean;
  soldAt?: number;
  soldPrice?: number;
  pnl: number;
  pnlPercent: number;
  currentPrice: number;
  currentMarketCap: number;
  bondingCurveProgress: number;
}

interface Stats {
  totalTrades: number;
  winCount: number;
  lossCount: number;
  totalPnl: number;
  totalPnlPercent: number;
  avgHoldingTime: number;
  bestTrade: TradePosition | null;
  worstTrade: TradePosition | null;
  currentPositions: number;
  graduatedTokens: number;
  balance: number;
  initialBalance: number;
}

interface LogMessage {
  id: string;
  timestamp: number;
  type: 'info' | 'success' | 'warning' | 'error' | 'trade' | 'graduation';
  message: string;
  details?: any;
}

// ===== Global Styles =====
const GlobalStyle = createGlobalStyle`
  * {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
  }

  body {
    background: linear-gradient(135deg, #0a0a0f 0%, #1a1a2e 50%, #16213e 100%);
    min-height: 100vh;
    color: #fff;
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  }
`;

// ===== Animations =====
const pulse = keyframes`
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
`;

const glow = keyframes`
  0%, 100% { box-shadow: 0 0 20px rgba(0, 255, 136, 0.3); }
  50% { box-shadow: 0 0 40px rgba(0, 255, 136, 0.6); }
`;

const slideIn = keyframes`
  from { transform: translateX(-100%); opacity: 0; }
  to { transform: translateX(0); opacity: 1; }
`;

// ===== Styled Components =====
const Dashboard = styled.div`
  max-width: 1600px;
  margin: 0 auto;
  padding: 20px;
`;

const Header = styled.header`
  text-align: center;
  margin-bottom: 30px;
  padding: 20px;
  background: linear-gradient(135deg, rgba(255,255,255,0.1) 0%, rgba(255,255,255,0.05) 100%);
  border-radius: 15px;
  border: 1px solid rgba(255,255,255,0.1);
`;

const Title = styled.h1`
  font-size: 2.5rem;
  background: linear-gradient(135deg, #00ff88, #00d4ff);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  margin-bottom: 10px;
`;

const Subtitle = styled.p`
  color: #888;
  font-size: 1.1rem;
`;

const Grid = styled.div`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
  margin-bottom: 20px;

  @media (max-width: 1200px) {
    grid-template-columns: 1fr;
  }
`;

const Card = styled.div`
  background: rgba(255,255,255,0.05);
  border-radius: 15px;
  padding: 20px;
  border: 1px solid rgba(255,255,255,0.1);
  backdrop-filter: blur(10px);
`;

const CardTitle = styled.h2`
  font-size: 1.3rem;
  margin-bottom: 15px;
  display: flex;
  align-items: center;
  gap: 10px;

  span {
    font-size: 1.5rem;
  }
`;

const StatsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 15px;
`;

const StatBox = styled.div<{ $positive?: boolean; $negative?: boolean; $highlight?: boolean }>`
  background: ${props => 
    props.$positive ? 'rgba(0, 255, 136, 0.15)' : 
    props.$negative ? 'rgba(255, 71, 87, 0.15)' : 
    props.$highlight ? 'rgba(0, 212, 255, 0.15)' : 
    'rgba(255,255,255,0.05)'
  };
  border-radius: 10px;
