// ===== Helper Functions =====
const formatTime = (timestamp: number) => format(timestamp, 'HH:mm:ss');
const formatDate = (timestamp: number) => format(timestamp, 'MM/dd HH:mm');

const formatNumber = (num: number, decimals: number = 4) => {
  if (Math.abs(num) < 0.0001) return num.toExponential(2);
  return num.toFixed(decimals);
};

const formatPercent = (num: number) => {
  const sign = num >= 0 ? '+' : '';
  return `${sign}${num.toFixed(2)}%`;
};

const formatSOL = (num: number) => `${num.toFixed(4)} SOL`;

const formatMarketCap = (num: number) => {
  if (num >= 1000000) return `$${(num / 1000000).toFixed(2)}M`;
  if (num >= 1000) return `$${(num / 1000).toFixed(2)}K`;
  return `$${num.toFixed(2)}`;
};

const formatRank = (rank: number) => {
  if (rank === 1) return '🥇 1st';
  if (rank === 2) return '🥈 2nd';
  if (rank === 3) return '🥉 3rd';
  if (rank <= 10) return `🔥 ${rank}th`;
  if (rank <= 50) return `⚡ ${rank}th`;
  return `${rank}th`;
};

// ===== Main Component =====
const App: React.FC = () => {
  const [socket, setSocket] = useState<Socket | null>(null);
  const [connected, setConnected] = useState(false);
  const [positions, setPositions] = useState<TradePosition[]>([]);
  const [stats, setStats] = useState<Stats | null>(null);
  const [logs, setLogs] = useState<LogMessage[]>([]);
  const logsEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll logs
  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  // Socket connection
  useEffect(() => {
    const newSocket = io('http://localhost:3001');
    setSocket(newSocket);

    newSocket.on('connect', () => {
      setConnected(true);
      addLog('info', '🔗 Connected to server');
    });

    newSocket.on('disconnect', () => {
      setConnected(false);
      addLog('error', '❌ Disconnected from server');
    });

    newSocket.on('init', (data) => {
      setPositions(data.positions || []);
      setStats({ ...data.stats, balance: data.balance, initialBalance: 100 });
      addLog('info', '📊 Initial data loaded');
    });

    newSocket.on('new_position', (position: TradePosition) => {
      setPositions(prev => [position, ...prev]);
      addLog('trade', `🎯 SNIPED: ${position.tokenName} at ${formatRank(position.buyRank)}!`, position);
    });

    newSocket.on('positions_update', (updatedPositions: TradePosition[]) => {
      setPositions(updatedPositions);
    });

    newSocket.on('position_update', (position: TradePosition) => {
      setPositions(prev => prev.map(p => p.id === position.id ? position : p));
    });

    newSocket.on('position_closed', (position: TradePosition) => {
      setPositions(prev => prev.filter(p => p.id !== position.id));
      const pnl = position.pnl;
      const type = pnl >= 0 ? 'success' : 'error';
      const emoji = pnl >= 0 ? '💰' : '💸';
      addLog(type, `${emoji} SOLD: ${position.tokenSymbol} | PnL: ${formatSOL(pnl)} (${formatPercent(position.pnlPercent)})`, position);
    });

    newSocket.on('token_created', (data) => {
      if (data.position) {
        addLog('success', data.message);
      }
    });

    newSocket.on('token_graduated', (data) => {
      setPositions(prev => prev.map(p => 
        p.tokenMint === data.mint ? { ...p, graduated: true, graduatedAt: Date.now() } : p
      ));
      addLog('graduation', `🎓 GRADUATED: ${data.tokenName}!`, data);
    });

    newSocket.on('stats_update', (updatedStats: Stats) => {
      setStats(updatedStats);
    });

    return () => {
      newSocket.close();
    };
  }, []);

  const addLog = (type: LogMessage['type'], message: string, details?: any) => {
    const newLog: LogMessage = {
      id: `${Date.now()}-${Math.random()}`,
      timestamp: Date.now(),
      type,
      message,
      details
    };
    setLogs(prev => [...prev.slice(-99), newLog]);
  };

  const handleReset = () => {
    fetch('http://localhost:3001/api/reset', { method: 'POST' })
      .then(() => {
        setPositions([]);
        addLog('info', '🔄 Paper trading reset');
      });
  };

  const handleSell = (mint: string, symbol: string) => {
    fetch(`http://localhost:3001/api/sell/${mint}`, { method: 'POST' })
      .then(res => res.json())
      .then(data => {
        if (data.success) {
          addLog('success', `✅ Manual sell: ${symbol}`);
        }
      });
  };

  return (
    <>
      <GlobalStyle />
      <Dashboard>
        <Header>
          <Title>🚀 Pump.fun Paper Sniper Bot</Title>
          <Subtitle>リアルタイムペーパートレードダッシュボード</Subtitle>
          <StatusIndicator $connected={connected}>
            {connected ? '🟢 Connected' : '🔴 Disconnected'}
          </StatusIndicator>
        </Header>

        {stats && (
          <Grid>
            <Card>
              <CardTitle><span>💰</span> Portfolio Overview</CardTitle>
              <StatsGrid>
                <StatBox $highlight>
                  <StatLabel>Balance</StatLabel>
                  <StatValue $color="#00d4ff">{formatSOL(stats.balance)}</StatValue>
                </StatBox>
                <StatBox $positive={stats.totalPnl >= 0} $negative={stats.totalPnl < 0}>
                  <StatLabel>Total PnL</StatLabel>
                  <StatValue $color={stats.totalPnl >= 0 ? '#00ff88' : '#ff4757'}>
                    {stats.totalPnl >= 0 ? '+' : ''}{formatSOL(stats.totalPnl)}
                  </StatValue>
                </StatBox>
                <StatBox>
                  <StatLabel>PnL %</StatLabel>
                  <StatValue $color={stats.totalPnlPercent >= 0 ? '#00ff88' : '#ff4757'}>
                    {formatPercent(stats.totalPnlPercent)}
                  </StatValue>
                </StatBox>
                <StatBox>
                  <StatLabel>Active Positions</StatLabel>
                  <StatValue>{stats.currentPositions} / 10</StatValue>
                </StatBox>
              </StatsGrid>
            </Card>

            <Card>
              <CardTitle><span>📊</span> Performance Stats</CardTitle>
              <StatsGrid>
                <StatBox $positive>
                  <StatLabel>Wins</StatLabel>
                  <StatValue $color="#00ff88">{stats.winCount}</StatValue>
                </StatBox>
                <StatBox $negative>
                  <StatLabel>Losses</StatLabel>
                  <StatValue $color="#ff4757">{stats.lossCount}</StatValue>
                </StatBox>
                <StatBox>
                  <StatLabel>Win Rate</StatLabel>
                  <StatValue>
                    {stats.totalTrades > 0 ? ((stats.winCount / stats.totalTrades) * 100).toFixed(1) : 0}%
                  </StatValue>
                </StatBox>
                <StatBox $highlight>
                  <StatLabel>Graduated</StatLabel>
                  <StatValue $color="#ffd700">{stats.graduatedTokens}</StatValue>
                </StatBox>
              </StatsGrid>
            </Card>
          </Grid>
        )}

        <Grid>
          <FullWidthCard>
            <CardTitle><span>📈</span> Active Positions
              <div style={{marginLeft: 'auto'}}>
                <Button onClick={handleReset}>🔄 Reset</Button>
              </div>
            </CardTitle>
            {positions.length === 0 ? (
              <div style={{textAlign: 'center', padding: '40px', color: '#666'}}>
                🎯 Waiting for new tokens...
              </div>
            ) : (
              <div style={{overflowX: 'auto'}}>
                <Table>
                  <thead>
                    <tr>
                      <Th>Token</Th>
                      <Th>Buy Rank</Th>
                      <Th>Entry</Th>
                      <Th>Current</Th>
                      <Th>Progress</Th>
                      <Th>PnL</Th>
                      <Th>Action</Th>
                    </tr>
                  </thead>
                  <tbody>
                    {positions.map((pos) => (
                      <Tr key={pos.id} $graduated={pos.graduated}>
                        <Td>
                          <strong>{pos.tokenName}</strong>
                          <br />
                          <span style={{color: '#888', fontSize: '0.85rem'}}>${pos.tokenSymbol}</span>
                          {pos.graduated && <Badge style={{marginLeft: '8px'}}>🎓 GRADUATED</Badge>}
                        </Td>
                        <Td>
                          <Badge>{formatRank(pos.buyRank)}</Badge>
                        </Td>
                        <Td>
                          <div>{formatSOL(pos.solAmount)}</div>
                          <div style={{color: '#888', fontSize: '0.8rem'}}>
                            {formatDate(pos.buyTime)}
                          </div>
                        </Td>
                        <Td>
                          <div>{formatMarketCap(pos.currentMarketCap)}</div>
                          <div style={{color: '#888', fontSize: '0.8rem'}}>
                            {formatNumber(pos.currentPrice, 9)} SOL/token
                          </div>
                        </Td>
                        <Td>
                          <div style={{display: 'flex', alignItems: 'center', gap: '8px'}}>
                            <span style={{minWidth: '45px'}}>{pos.bondingCurveProgress.toFixed(1)}%</span>
                            <ProgressBar $progress={pos.bondingCurveProgress} />
                          </div>
                        </Td>
                        <Td $positive={pos.pnl > 0} $negative={pos.pnl < 0}>
                          <div style={{fontWeight: 'bold'}}>
                            {pos.pnl >= 0 ? '+' : ''}{formatSOL(pos.pnl)}
                          </div>
                          <div style={{fontSize: '0.85rem'}}>
                            {formatPercent(pos.pnlPercent)}
                          </div>
                        </Td>
                        <Td>
                          <Button onClick={() => handleSell(pos.tokenMint, pos.tokenSymbol)}>
                            💰 Sell
                          </Button>
                        </Td>
                      </Tr>
                    ))}
                  </tbody>
                </Table>
              </div>
            )}
          </FullWidthCard>
        </Grid>

        <Grid>
          <Card>
            <CardTitle><span>📝</span> Best Trade</CardTitle>
            {stats?.bestTrade ? (
              <div>
                <div style={{fontSize: '1.2rem', fontWeight: 'bold', marginBottom: '10px'}}>
                  {stats.bestTrade.tokenName} (${stats.bestTrade.tokenSymbol})
                </div>
                <div style={{color: '#00ff88', fontSize: '1.5rem', fontWeight: 'bold'}}>
                  +{formatSOL(stats.bestTrade.pnl)} ({formatPercent(stats.bestTrade.pnlPercent)})
                </div>
                <div style={{color: '#888', marginTop: '10px'}}>
                  Entry Rank: {formatRank(stats.bestTrade.buyRank)}
                </div>
              </div>
            ) : (
              <div style={{color: '#666'}}>No completed trades yet</div>
            )}
          </Card>

          <Card>
            <CardTitle><span>⚠️</span> Worst Trade</CardTitle>
            {stats?.worstTrade ? (
              <div>
                <div style={{fontSize: '1.2rem', fontWeight: 'bold', marginBottom: '10px'}}>
                  {stats.worstTrade.tokenName} (${stats.worstTrade.tokenSymbol})
                </div>
                <div style={{color: '#ff4757', fontSize: '1.5rem', fontWeight: 'bold'}}>
                  {formatSOL(stats.worstTrade.pnl)} ({formatPercent(stats.worstTrade.pnlPercent)})
                </div>
                <div style={{color: '#888', marginTop: '10px'}}>
                  Entry Rank: {formatRank(stats.worstTrade.buyRank)}
                </div>
              </div>
            ) : (
              <div style={{color: '#666'}}>No completed trades yet</div>
            )}
          </Card>
        </Grid>

        <Card>
          <CardTitle><span>📜</span> Live Activity Log</CardTitle>
          <LogContainer>
            {logs.length === 0 ? (
              <div style={{color: '#666', textAlign: 'center', padding: '20px'}}>
                🚀 Waiting for activity...
              </div>
            ) : (
              logs.map((log) => (
                <LogItem key={log.id} $type={log.type}>
                  <LogTime>{formatTime(log.timestamp)}</LogTime>
                  {log.message}
                </LogItem>
              ))
            )}
            <div ref={logsEndRef} />
          </LogContainer>
        </Card>
      </Dashboard>
    </>
  );
};

export default App;
